434→    #[test]
435→    fn test_full_keep_discard_cycle() {
436→        let (ops, dir) = setup_repo();
437→        ops.create_branch("cycle-test").expect("create_branch");
438→
439→        // --- Iteration 1: KEEP ---
440→        // Create a file and commit (keep the mutation).
441→        let kept_path = dir.path().join("kept.txt");
442→        fs::write(&kept_path, "I am kept\n").expect("write kept");
443→        let keep_sha = ops.commit("keep iteration 1").expect("commit");
444→
445→        // File must exist after keep.
446→        assert!(kept_path.exists(), "kept.txt must exist after keep");
447→
448→        // --- Iteration 2: DISCARD ---
449→        // Create another file but do NOT commit (discard the mutation).
450→        let discarded_path = dir.path().join("discarded.txt");
451→        fs::write(&discarded_path, "I should be gone\n").expect("write discarded");
452→        assert!(discarded_path.exists(), "discarded.txt must exist before discard");
453→
454→        // Reset to last keep.
455→        ops.reset_to_last_keep().expect("reset_to_last_keep");
456→
457→        // Kept file must still exist.
458→        assert!(kept_path.exists(), "kept.txt must survive discard");
459→        assert_eq!(
460→            fs::read_to_string(&kept_path).expect("read kept"),
461→            "I am kept\n"
462→        );
463→
464→        // HEAD must be at the keep commit.
465→        assert_eq!(
466→            ops.head_sha().expect("head_sha"),
467→            keep_sha,
468→            "HEAD must be at the keep commit after discard"
469→        );
470→    }
