        let (ops, dir) = setup_trait_ops();
        ops.create_branch("trait-multi").expect("create_branch");

        // Cycle 1: keep
        fs::write(dir.path().join("iter1.txt"), "one\n").expect("write");
        let sha1 = ops.commit("iteration 1").expect("commit 1");

        // Cycle 2: discard
        fs::write(dir.path().join("iter2_bad.txt"), "bad\n").expect("write");
        ops.reset_to_last_keep().expect("discard 2");
        assert_eq!(ops.head_sha().expect("head"), sha1);
        assert!(!dir.path().join("iter2_bad.txt").exists());

        // Cycle 3: keep
        fs::write(dir.path().join("iter3.txt"), "three\n").expect("write");
        let sha3 = ops.commit("iteration 3").expect("commit 3");
        assert_ne!(sha1, sha3);

        // Cycle 4: discard
        fs::write(dir.path().join("iter4_bad.txt"), "bad\n").expect("write");
        ops.reset_to_last_keep().expect("discard 4");
        assert_eq!(ops.head_sha().expect("head"), sha3);
        assert!(!dir.path().join("iter4_bad.txt").exists());

        // Verify all kept files still exist.
        assert!(dir.path().join("iter1.txt").exists());
        assert!(dir.path().join("iter3.txt").exists());
    }

